    84→// addPrefixWrapper wraps a prometheus.Gatherer, and ensures that all metric names are prefixed with `grafana_`.
    85→// metrics with the prefix `grafana_` or `go_` are not modified.
    86→type addPrefixWrapper struct {
    87→	orig prometheus.Gatherer
    88→	reg  *regexp.Regexp
    89→}
    90→
    91→func newAddPrefixWrapper(orig prometheus.Gatherer) *addPrefixWrapper {
    92→	return &addPrefixWrapper{
    93→		orig: orig,
    94→		reg:  regexp.MustCompile("^((?:grafana_|go_).*)"),
    95→	}
    96→}
