    98→func (g *addPrefixWrapper) Gather() ([]*dto.MetricFamily, error) {
    99→	mf, err := g.orig.Gather()
   100→	if err != nil {
   101→		return nil, err
   102→	}
   103→
   104→	names := make(map[string]struct{})
   105→
   106→	for i := 0; i < len(mf); i++ {
   107→		m := mf[i]
   108→		if m.Name != nil && !g.reg.MatchString(*m.Name) {
   109→			*m.Name = "grafana_" + *m.Name
   110→			// since we are modifying the name, we need to check for duplicates in the gatherer
   111→			if _, exists := names[*m.Name]; exists {
   112→				return nil, fmt.Errorf("duplicate metric name: %s", *m.Name)
   113→			}
   114→		}
   115→		// keep track of names to detect duplicates
   116→		names[*m.Name] = struct{}{}
   117→	}
   118→
   119→	return mf, nil
   120→}
