   134→func (r *multiRegistry) Gather() (mfs []*dto.MetricFamily, err error) {
   135→	errs := prometheus.MultiError{}
   136→
   137→	names := make(map[string]struct{})
   138→	for _, g := range r.gatherers {
   139→		mf, err := g.Gather()
   140→		errs.Append(err)
   141→
   142→		for i := 0; i < len(mf); i++ {
   143→			m := mf[i]
   144→			_, exists := names[*m.Name]
   145→			// prevent duplicate metric names
   146→			if exists {
   147→				// we can skip go_ metrics without returning an error
   148→				// because they are known to be duplicates in both
   149→				// the k8s and prometheus gatherers.
   150→				if strings.HasPrefix(*m.Name, "go_") {
   151→					continue
   152→				}
   153→				errs = append(errs, fmt.Errorf("duplicate metric name: %s", *m.Name))
   154→				continue
   155→			}
   156→			names[*m.Name] = struct{}{}
   157→			mfs = append(mfs, m)
   158→		}
   159→	}
   160→
   161→	sort.Slice(mfs, func(i, j int) bool {
   162→		return *mfs[i].Name < *mfs[j].Name
   163→	})
   164→
   165→	return mfs, errs.MaybeUnwrap()
